"""
自动生成：将 templates/*.html 内容内嵌为字典，供 DictLoader 从内存加载
(EdgeOne 云函数构建器不打包 templates/ 这类非 .py 静态资源)
"""
TEMPLATES = {
  "about.html": "{% extends \"base.html\" %}\n{% block title %}关于{% endblock %}\n{% block content %}\n<div class=\"module-header\">\n    <div class=\"container\">\n        <h2>关于 AI 内容创作系统</h2>\n        <p class=\"mb-0 opacity-75\">北极星·炼术师 · 腾讯 AI 黑客松 · 方向二【内容】</p>\n    </div>\n</div>\n<div class=\"container\">\n    <div class=\"row g-4\">\n        <div class=\"col-lg-8\">\n            <div class=\"card\">\n                <div class=\"card-body\">\n                    <h4>🎯 解决什么问题</h4>\n                    <p>内容创作者最痛的三个环节：<strong>选题没方向、爆款学不到、多平台改稿累</strong>。我们用 AI + 结构化方法论，把创作从\"凭感觉\"变成\"有数据、有方法、可迭代\"。</p>\n\n                    <h4 class=\"mt-4\">🧩 四大模块 + 素材库</h4>\n                    <div class=\"row g-3 mt-2\">\n                        <div class=\"col-md-6\"><div class=\"border rounded p-3\"><strong>1. 选题脑暴</strong><br><small class=\"text-muted\">6 角度、6 钩子，热度预估</small></div></div>\n                        <div class=\"col-md-6\"><div class=\"border rounded p-3\"><strong>2. 爆款拆解</strong><br><small class=\"text-muted\">结构 + 情绪节点 + 可复用框架</small></div></div>\n                        <div class=\"col-md-6\"><div class=\"border rounded p-3\"><strong>3. 多平台适配</strong><br><small class=\"text-muted\">5 大平台调性一键改写</small></div></div>\n                        <div class=\"col-md-6\"><div class=\"border rounded p-3\"><strong>4. 标题 AB</strong><br><small class=\"text-muted\">点击率打分 + 优化建议</small></div></div>\n                        <div class=\"col-md-12\"><div class=\"border rounded p-3\"><strong>+ 私有素材库</strong><br><small class=\"text-muted\">BM25 检索，让 AI 用上你的私有语料</small></div></div>\n                    </div>\n\n                    <h4 class=\"mt-4\">🛠️ 技术架构</h4>\n                    <ul>\n                        <li><strong>后端</strong>：Python 3.11 + Flask + SQLite</li>\n                        <li><strong>AI</strong>：OpenAI GPT-4o（可切 Mock）</li>\n                        <li><strong>检索</strong>：BM25（含中英文分词）</li>\n                        <li><strong>文档解析</strong>：pdftotext / python-docx</li>\n                        <li><strong>前端</strong>：Bootstrap 5</li>\n                    </ul>\n\n                    <h4 class=\"mt-4\">💡 差异化亮点</h4>\n                    <ol>\n                        <li><strong>专家 Prompt 库</strong>：每个模块的 System Prompt 由内容创作专家调优过</li>\n                        <li><strong>私有语料增强</strong>：AI 在选题/拆解时会自动引用你上传的爆款/灵感</li>\n                        <li><strong>创作动作闭环</strong>：脑暴 → 拆解 → 适配 → 标题 AB 一路直达</li>\n                        <li><strong>Mock 降级保护</strong>：真实 AI 不可用时自动兜底</li>\n                    </ol>\n                </div>\n            </div>\n        </div>\n        <div class=\"col-lg-4\">\n            <div class=\"card mb-3\">\n                <div class=\"card-body text-center\">\n                    <div style=\"font-size:5rem; color:#f472b6; text-shadow:0 0 30px rgba(244,114,182,.5);\">✦</div>\n                    <h4 class=\"mb-1\">北极星 · 炼术师</h4>\n                    <p class=\"text-muted mb-2\">Polaris Alchemists</p>\n                    <p class=\"small\">🌟 AI 炼真金 · 专业落地</p>\n                </div>\n            </div>\n            <div class=\"card\">\n                <div class=\"card-header\">📦 相关资源</div>\n                <div class=\"card-body\">\n                    <p class=\"small mb-1\"><strong>本仓库</strong></p>\n                    <a href=\"https://git.woa.com/csc/ai-content-creator\" target=\"_blank\" class=\"small\">git.woa.com/csc/ai-content-creator</a>\n                    <p class=\"small mb-1 mt-3\"><strong>姊妹作品</strong></p>\n                    <a href=\"https://git.woa.com/csc/ai-sales-assistant\" target=\"_blank\" class=\"small\">AI 销售助理（方向三）</a>\n                </div>\n            </div>\n        </div>\n    </div>\n</div>\n{% endblock %}\n",
  "base.html": "<!DOCTYPE html>\n<html lang=\"zh-CN\">\n<head>\n    <meta charset=\"UTF-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n    <title>{% block title %}AI 内容创作系统 | 北极星·炼术师{% endblock %}</title>\n    <link href=\"https://cdn.jsdelivr.net/npm/bootstrap@5.3.0/dist/css/bootstrap.min.css\" rel=\"stylesheet\">\n    <link href=\"https://cdn.jsdelivr.net/npm/bootstrap-icons@1.11.1/font/bootstrap-icons.css\" rel=\"stylesheet\">\n    <style>\n        :root {\n            --primary: #4c1d95;\n            --primary-2: #7c3aed;\n            --accent: #f472b6;\n            --gold: #fbbf24;\n            --light-bg: #faf7ff;\n        }\n        body {\n            font-family: -apple-system, \"PingFang SC\", \"Microsoft YaHei\", sans-serif;\n            background: var(--light-bg);\n            color: #1a1a2e;\n        }\n        .navbar {\n            background: linear-gradient(135deg, var(--primary), var(--primary-2)) !important;\n            box-shadow: 0 2px 10px rgba(76,29,149,.3);\n        }\n        .navbar-brand, .navbar .nav-link { color: #fff !important; }\n        .navbar-brand { font-weight: 700; font-size: 1.25rem; }\n        .navbar-brand .brand-star { color: var(--accent); margin-right: 6px; }\n        .nav-link { padding: .5rem .85rem !important; font-size: .95rem; }\n        .nav-link:hover, .nav-link.active { color: var(--accent) !important; }\n        .llm-badge {\n            font-size: .72rem; padding: 2px 8px; border-radius: 10px;\n            margin-left: 8px; vertical-align: middle;\n        }\n        .llm-badge.real { background: #10b981; color: #fff; }\n        .llm-badge.mock { background: #f59e0b; color: #fff; }\n\n        .hero-section {\n            background: linear-gradient(135deg, var(--primary) 0%, var(--primary-2) 50%, #db2777 100%);\n            color: white; padding: 90px 0 100px;\n            position: relative; overflow: hidden;\n        }\n        .hero-section::before {\n            content: ''; position: absolute; inset: 0;\n            background:\n                radial-gradient(circle at 20% 30%, rgba(244,114,182,.2), transparent 40%),\n                radial-gradient(circle at 80% 70%, rgba(251,191,36,.15), transparent 40%);\n        }\n        .feature-card {\n            border: none; border-radius: 14px;\n            transition: transform .3s, box-shadow .3s;\n            height: 100%; background: #fff;\n        }\n        .feature-card:hover {\n            transform: translateY(-4px);\n            box-shadow: 0 12px 30px rgba(124,58,237,.15);\n        }\n        .feature-icon { font-size: 2.4rem; color: var(--primary-2); margin-bottom: 12px; }\n        .btn-primary {\n            background: var(--primary-2); border-color: var(--primary-2);\n        }\n        .btn-primary:hover, .btn-primary:focus {\n            background: var(--primary); border-color: var(--primary);\n        }\n        .btn-accent {\n            background: var(--accent); color: #fff; border: none; font-weight: 600;\n        }\n        .btn-accent:hover { background: #db2777; color: #fff; }\n\n        .module-header {\n            background: linear-gradient(135deg, var(--primary), var(--primary-2));\n            color: white; padding: 50px 0 40px; margin-bottom: 30px;\n        }\n        .result-card { border-left: 4px solid var(--primary-2); background: #fff; border-radius: 8px; }\n        .tips-box {\n            background: #fef3c7; border-left: 4px solid var(--gold);\n            padding: 14px 16px; border-radius: 6px;\n        }\n        .source-tag {\n            display: inline-block; font-size: .75rem;\n            padding: 2px 8px; border-radius: 10px; margin-left: 8px;\n        }\n        .source-tag.real { background: #d1fae5; color: #065f46; }\n        .source-tag.mock { background: #fef3c7; color: #92400e; }\n\n        footer {\n            background: var(--primary); color: rgba(255,255,255,.85);\n            padding: 30px 0 20px; margin-top: 60px;\n        }\n        footer a { color: var(--accent); text-decoration: none; }\n        .loading-spinner {\n            display: inline-block; width: 1.2rem; height: 1.2rem;\n            border: 2px solid rgba(255,255,255,.3); border-top-color: #fff;\n            border-radius: 50%; animation: spin .8s linear infinite;\n        }\n        @keyframes spin { to { transform: rotate(360deg); } }\n    </style>\n    {% block extra_css %}{% endblock %}\n</head>\n<body>\n    <nav class=\"navbar navbar-expand-lg\">\n        <div class=\"container\">\n            <a class=\"navbar-brand\" href=\"/\">\n                <span class=\"brand-star\">✦</span> AI 内容创作系统\n                <span class=\"llm-badge\" id=\"llm-badge\">…</span>\n            </a>\n            <button class=\"navbar-toggler\" type=\"button\" data-bs-toggle=\"collapse\" data-bs-target=\"#navbarNav\">\n                <span class=\"navbar-toggler-icon\"></span>\n            </button>\n            <div class=\"collapse navbar-collapse\" id=\"navbarNav\">\n                <ul class=\"navbar-nav ms-auto\">\n                    <li class=\"nav-item\"><a class=\"nav-link\" href=\"/\">首页</a></li>\n                    <li class=\"nav-item\"><a class=\"nav-link\" href=\"/topic-brainstorm\"><i class=\"bi bi-lightbulb\"></i> 选题脑暴</a></li>\n                    <li class=\"nav-item\"><a class=\"nav-link\" href=\"/viral-analysis\"><i class=\"bi bi-fire\"></i> 爆款拆解</a></li>\n                    <li class=\"nav-item\"><a class=\"nav-link\" href=\"/platform-adaptation\"><i class=\"bi bi-arrow-left-right\"></i> 多平台适配</a></li>\n                    <li class=\"nav-item\"><a class=\"nav-link\" href=\"/title-ab-test\"><i class=\"bi bi-type-h1\"></i> 标题 AB</a></li>\n                    <li class=\"nav-item\"><a class=\"nav-link\" href=\"/library\"><i class=\"bi bi-folder\"></i> 素材库</a></li>\n                    <li class=\"nav-item\"><a class=\"nav-link\" href=\"/about\"><i class=\"bi bi-info-circle\"></i> 关于</a></li>\n                </ul>\n            </div>\n        </div>\n    </nav>\n\n    <main>{% block content %}{% endblock %}</main>\n\n    <footer>\n        <div class=\"container\">\n            <div class=\"row\">\n                <div class=\"col-md-6\">\n                    <h5>✦ 北极星 · 炼术师</h5>\n                    <p class=\"mb-1\">AI 内容创作系统 - WorkBuddy 专业领域生产系统</p>\n                    <small>方向二【内容】· 腾讯 AI 黑客松参赛作品</small>\n                </div>\n                <div class=\"col-md-6 text-md-end\">\n                    <p class=\"mb-1\">🌟 AI 炼真金 · 专业落地</p>\n                    <small>© 2024 Polaris Alchemists</small>\n                </div>\n            </div>\n        </div>\n    </footer>\n\n    <script src=\"https://cdn.jsdelivr.net/npm/bootstrap@5.3.0/dist/js/bootstrap.bundle.min.js\"></script>\n    <script>\n        // 全局兜底：把 AI 返回的任意类型（字符串/数字/数组/对象）安全转成可读文本，\n        // 避免 AI 偏离约定的字段类型时前端出现 [object Object] 乱码。\n        function safeText(v, sep) {\n            sep = sep || '；';\n            if (v === null || v === undefined) return '';\n            if (typeof v === 'string') return v;\n            if (typeof v === 'number' || typeof v === 'boolean') return String(v);\n            if (Array.isArray(v)) return v.map(x => safeText(x, sep)).filter(Boolean).join(sep);\n            if (typeof v === 'object') return Object.values(v).map(x => safeText(x, sep)).filter(Boolean).join(' ');\n            return String(v);\n        }\n        // 专用于\"分步骤\"类字段（如切入策略）：数组会编号展示，字符串原样返回\n        function safeSteps(v) {\n            if (Array.isArray(v)) return v.map((item, i) => `${i + 1}. ${safeText(item)}`).join('\\n');\n            return safeText(v);\n        }\n\n        fetch('/api/system/info').then(r => r.json()).then(d => {\n            const b = document.getElementById('llm-badge');\n            if (!b) return;\n            if (d.llm_mode === 'real') { b.className = 'llm-badge real'; b.textContent = 'AI · ' + (d.model || 'gpt-4o'); }\n            else { b.className = 'llm-badge mock'; b.textContent = 'Mock 演示'; }\n        }).catch(() => {});\n        const path = location.pathname;\n        document.querySelectorAll('.navbar-nav .nav-link').forEach(a => { if (a.getAttribute('href') === path) a.classList.add('active'); });\n    </script>\n    {% block extra_js %}{% endblock %}\n</body>\n</html>\n",
  "index.html": "{% extends \"base.html\" %}\n{% block title %}AI 内容创作系统 · 首页{% endblock %}\n{% block content %}\n<section class=\"hero-section\">\n    <div class=\"container position-relative\">\n        <div class=\"row align-items-center\">\n            <div class=\"col-lg-7\">\n                <h6 class=\"text-uppercase mb-2\" style=\"letter-spacing:2px; color:#f472b6;\">Polaris Alchemists · 北极星·炼术师</h6>\n                <h1 class=\"display-4 fw-bold mb-3\">AI 内容创作系统</h1>\n                <p class=\"lead mb-4\">从灵感到爆款，一站式创作助手<br>\n                    选题脑暴 · 爆款拆解 · 多平台适配 · 标题打分 —— 让每一次创作都有数据支撑</p>\n                <div class=\"d-flex gap-2 flex-wrap\">\n                    <a href=\"/topic-brainstorm\" class=\"btn btn-accent btn-lg\"><i class=\"bi bi-lightning-charge\"></i> 开始创作</a>\n                    <a href=\"/about\" class=\"btn btn-outline-light btn-lg\">了解方案</a>\n                </div>\n            </div>\n            <div class=\"col-lg-5 text-center d-none d-lg-block\">\n                <div style=\"font-size:12rem; line-height:1; text-shadow:0 0 40px rgba(244,114,182,.6);\">✦</div>\n            </div>\n        </div>\n    </div>\n</section>\n\n<div class=\"container py-5\">\n    <div class=\"text-center mb-5\">\n        <h2 class=\"fw-bold\">四大核心模块 + 私有素材库</h2>\n        <p class=\"text-muted\">让创作从\"凭感觉\"变成\"有方法\"</p>\n    </div>\n    <div class=\"row g-4\">\n        <div class=\"col-md-6 col-lg-4\">\n            <a href=\"/topic-brainstorm\" class=\"text-decoration-none text-dark\">\n                <div class=\"card feature-card p-4\">\n                    <div class=\"feature-icon\"><i class=\"bi bi-lightbulb\"></i></div>\n                    <h5>选题脑暴</h5>\n                    <p class=\"text-muted small\">输入主题，AI 从 6 个角度给出候选选题，附热度预估</p>\n                </div>\n            </a>\n        </div>\n        <div class=\"col-md-6 col-lg-4\">\n            <a href=\"/viral-analysis\" class=\"text-decoration-none text-dark\">\n                <div class=\"card feature-card p-4\">\n                    <div class=\"feature-icon\"><i class=\"bi bi-fire\"></i></div>\n                    <h5>爆款拆解</h5>\n                    <p class=\"text-muted small\">粘贴一篇爆款，AI 拆结构、找情绪节点、给出可复用框架</p>\n                </div>\n            </a>\n        </div>\n        <div class=\"col-md-6 col-lg-4\">\n            <a href=\"/platform-adaptation\" class=\"text-decoration-none text-dark\">\n                <div class=\"card feature-card p-4\">\n                    <div class=\"feature-icon\"><i class=\"bi bi-arrow-left-right\"></i></div>\n                    <h5>多平台适配</h5>\n                    <p class=\"text-muted small\">一稿改多稿：公众号/小红书/知乎/视频号/LinkedIn</p>\n                </div>\n            </a>\n        </div>\n        <div class=\"col-md-6 col-lg-4\">\n            <a href=\"/title-ab-test\" class=\"text-decoration-none text-dark\">\n                <div class=\"card feature-card p-4\">\n                    <div class=\"feature-icon\"><i class=\"bi bi-type-h1\"></i></div>\n                    <h5>标题 AB 测试</h5>\n                    <p class=\"text-muted small\">6 个不同风格候选标题 + 点击率打分，选最优发</p>\n                </div>\n            </a>\n        </div>\n        <div class=\"col-md-6 col-lg-4\">\n            <a href=\"/library\" class=\"text-decoration-none text-dark\">\n                <div class=\"card feature-card p-4\">\n                    <div class=\"feature-icon\"><i class=\"bi bi-folder\"></i></div>\n                    <h5>私有素材库</h5>\n                    <p class=\"text-muted small\">上传灵感/参考文/历史稿，AI 生成时自动检索复用</p>\n                </div>\n            </a>\n        </div>\n        <div class=\"col-md-6 col-lg-4\">\n            <a href=\"/about\" class=\"text-decoration-none text-dark\">\n                <div class=\"card feature-card p-4\">\n                    <div class=\"feature-icon\"><i class=\"bi bi-stars\"></i></div>\n                    <h5>关于我们</h5>\n                    <p class=\"text-muted small\">团队介绍、技术架构、参赛信息</p>\n                </div>\n            </a>\n        </div>\n    </div>\n\n    <div class=\"mt-5 p-4 rounded\" style=\"background: linear-gradient(135deg, #fdf4ff, #ede9fe);\">\n        <div class=\"row align-items-center\">\n            <div class=\"col-md-8\">\n                <h5 class=\"mb-2\">🚀 为什么用它？</h5>\n                <p class=\"mb-0 text-muted\">通用 AI 只会写\"看似合理\"的内容，我们在每一步注入创作者思维：选题看角度差异、拆解看情绪节点、适配看平台调性、标题看点击率预估。<strong>让创作既有 AI 的效率，又有专业创作者的判断力。</strong></p>\n            </div>\n            <div class=\"col-md-4 text-md-end mt-3 mt-md-0\">\n                <a href=\"/topic-brainstorm\" class=\"btn btn-primary\">开始第一次脑暴 →</a>\n            </div>\n        </div>\n    </div>\n</div>\n{% endblock %}\n",
  "library.html": "{% extends \"base.html\" %}\n{% block title %}素材库{% endblock %}\n{% block content %}\n<div class=\"module-header\">\n    <div class=\"container\">\n        <h2><i class=\"bi bi-folder\"></i> 私有素材库</h2>\n        <p class=\"mb-0 opacity-75\">上传灵感、参考爆款、自己写过的稿子 —— AI 生成选题/拆解时自动检索复用</p>\n    </div>\n</div>\n<div class=\"container\">\n    <div class=\"row g-4\">\n        <div class=\"col-lg-5\">\n            <div class=\"card\">\n                <div class=\"card-header\"><i class=\"bi bi-cloud-upload\"></i> 上传素材</div>\n                <div class=\"card-body\">\n                    <form id=\"upload-form\">\n                        <div class=\"mb-3\">\n                            <label class=\"form-label\">选择文件</label>\n                            <input type=\"file\" class=\"form-control\" id=\"file\" required accept=\".txt,.md,.pdf,.docx,.doc,.csv,.json\">\n                            <small class=\"text-muted\">支持 txt/md/pdf/docx/csv/json，最大 20 MB</small>\n                        </div>\n                        <div class=\"mb-3\">\n                            <label class=\"form-label\">分类</label>\n                            <select class=\"form-select\" id=\"category\">\n                                <option>通用</option><option>灵感笔记</option>\n                                <option>爆款参考</option><option>历史稿件</option>\n                                <option>选题库</option><option>金句库</option>\n                            </select>\n                        </div>\n                        <div class=\"mb-3\">\n                            <label class=\"form-label\">标签（可选）</label>\n                            <input class=\"form-control\" id=\"tags\" placeholder=\"如：小红书,育儿,情感\">\n                        </div>\n                        <button class=\"btn btn-primary w-100\" id=\"btn-upload\"><i class=\"bi bi-upload\"></i> 上传</button>\n                    </form>\n                </div>\n            </div>\n\n            <div class=\"card mt-4\">\n                <div class=\"card-header\"><i class=\"bi bi-search\"></i> 检索测试</div>\n                <div class=\"card-body\">\n                    <div class=\"input-group\">\n                        <input class=\"form-control\" id=\"q\" placeholder=\"输入关键词\">\n                        <button class=\"btn btn-primary\" id=\"btn-search\"><i class=\"bi bi-search\"></i></button>\n                    </div>\n                    <div id=\"hits\" class=\"mt-3\"></div>\n                </div>\n            </div>\n        </div>\n        <div class=\"col-lg-7\">\n            <div class=\"card\">\n                <div class=\"card-header d-flex justify-content-between align-items-center\">\n                    <span><i class=\"bi bi-list-ul\"></i> 素材列表</span>\n                    <button class=\"btn btn-sm btn-outline-primary\" onclick=\"loadList()\"><i class=\"bi bi-arrow-clockwise\"></i></button>\n                </div>\n                <div class=\"card-body\"><div id=\"doc-list\">加载中…</div></div>\n            </div>\n        </div>\n    </div>\n</div>\n\n<script>\nasync function loadList() {\n    const r = await fetch('/api/library/list').then(r => r.json());\n    const box = document.getElementById('doc-list');\n    if (!r.docs.length) { box.innerHTML = '<p class=\"text-muted text-center py-4\">还没有素材</p>'; return; }\n    box.innerHTML = '<table class=\"table table-hover\"><thead><tr><th>文件名</th><th>分类</th><th>标签</th><th></th></tr></thead><tbody>' +\n        r.docs.map(d => `<tr>\n            <td>${d.filename}</td>\n            <td><span class=\"badge bg-secondary\">${d.category}</span></td>\n            <td><small>${d.tags || '-'}</small></td>\n            <td><button class=\"btn btn-sm btn-outline-danger\" onclick=\"del(${d.id})\"><i class=\"bi bi-trash\"></i></button></td>\n        </tr>`).join('') + '</tbody></table>';\n}\nasync function del(id) { if (!confirm('删除？')) return; await fetch('/api/library/delete/' + id, {method: 'DELETE'}); loadList(); }\n\ndocument.getElementById('upload-form').onsubmit = async e => {\n    e.preventDefault();\n    const f = document.getElementById('file').files[0]; if (!f) return;\n    const fd = new FormData();\n    fd.append('file', f);\n    fd.append('category', document.getElementById('category').value);\n    fd.append('tags', document.getElementById('tags').value);\n    const btn = document.getElementById('btn-upload');\n    btn.disabled = true; btn.innerHTML = '<span class=\"loading-spinner\"></span> 上传中…';\n    try {\n        const r = await fetch('/api/library/upload', {method: 'POST', body: fd}).then(r => r.json());\n        if (r.success) { alert('上传成功'); e.target.reset(); loadList(); } else alert('失败：' + r.error);\n    } catch (e) { alert('失败：' + e); }\n    btn.disabled = false; btn.innerHTML = '<i class=\"bi bi-upload\"></i> 上传';\n};\n\ndocument.getElementById('btn-search').onclick = async () => {\n    const q = document.getElementById('q').value.trim(); if (!q) return;\n    const r = await fetch('/api/library/search?q=' + encodeURIComponent(q)).then(r => r.json());\n    const box = document.getElementById('hits');\n    if (!r.hits.length) { box.innerHTML = '<small class=\"text-muted\">无匹配</small>'; return; }\n    box.innerHTML = r.hits.map(h => `<div class=\"border rounded p-2 mb-2 small\"><strong>${h.filename}</strong> <span class=\"badge bg-info\">${h.score}</span><div class=\"text-muted mt-1\">${h.snippet.substring(0,150)}…</div></div>`).join('');\n};\n\nloadList();\n</script>\n{% endblock %}\n",
  "platform_adaptation.html": "{% extends \"base.html\" %}\n{% block title %}多平台适配{% endblock %}\n{% block content %}\n<div class=\"module-header\">\n    <div class=\"container\">\n        <h2><i class=\"bi bi-arrow-left-right\"></i> 多平台适配</h2>\n        <p class=\"mb-0 opacity-75\">一稿多平台：AI 根据平台调性改写正文、生成标题、封面建议</p>\n    </div>\n</div>\n<div class=\"container\">\n    <div class=\"row g-4\">\n        <div class=\"col-lg-5\">\n            <div class=\"card\">\n                <div class=\"card-body\">\n                    <label class=\"form-label fw-bold\">目标平台</label>\n                    <select class=\"form-select\" id=\"platform\">\n                        <option>公众号</option><option>小红书</option>\n                        <option>知乎</option><option>视频号</option><option>LinkedIn</option>\n                    </select>\n                    <label class=\"form-label fw-bold mt-3\">原稿 *</label>\n                    <textarea class=\"form-control\" id=\"content\" rows=\"12\" placeholder=\"粘贴原始稿件…\"></textarea>\n                    <button class=\"btn btn-primary w-100 mt-3\" id=\"btn-go\"><i class=\"bi bi-arrow-repeat\"></i> 一键适配</button>\n                </div>\n            </div>\n        </div>\n        <div class=\"col-lg-7\">\n            <div id=\"result\" class=\"d-none\">\n                <div class=\"card result-card mb-3\">\n                    <div class=\"card-body\">\n                        <div class=\"d-flex justify-content-between align-items-center mb-3\">\n                            <h5 class=\"mb-0\">📱 <span id=\"r-platform\"></span> 适配版 <span class=\"source-tag\" id=\"r-source\"></span></h5>\n                            <button class=\"btn btn-sm btn-outline-primary\" id=\"btn-copy\"><i class=\"bi bi-clipboard\"></i> 复制正文</button>\n                        </div>\n\n                        <h6>📝 改写后的正文</h6>\n                        <pre id=\"r-content\" style=\"white-space:pre-wrap; font-family:inherit; background:#faf7ff; padding:15px; border-radius:6px; max-height:400px; overflow-y:auto;\">-</pre>\n\n                        <div class=\"row g-3 mt-2\">\n                            <div class=\"col-12\">\n                                <h6>💡 标题建议</h6>\n                                <ul id=\"r-titles\"></ul>\n                            </div>\n                            <div class=\"col-md-6\"><div class=\"border rounded p-3 h-100\"><small class=\"text-muted\">封面建议</small><div class=\"mt-1\" id=\"r-cover\"></div></div></div>\n                            <div class=\"col-md-6\"><div class=\"border rounded p-3 h-100\"><small class=\"text-muted\">最佳发布时间</small><div class=\"mt-1 fw-bold\" id=\"r-time\"></div></div></div>\n                            <div class=\"col-12\">\n                                <small class=\"text-muted\">推荐标签：</small>\n                                <div id=\"r-tags\" class=\"mt-1\"></div>\n                            </div>\n                        </div>\n                    </div>\n                </div>\n            </div>\n            <div id=\"empty\" class=\"text-center text-muted py-5\">\n                <div style=\"font-size:4rem;\">🔀</div>\n                <p>选平台 + 粘原稿，一键适配</p>\n            </div>\n        </div>\n    </div>\n</div>\n\n<script>\ndocument.getElementById('btn-go').onclick = async () => {\n    const content = document.getElementById('content').value.trim();\n    if (!content) { alert('请填原稿'); return; }\n    const body = {platform: document.getElementById('platform').value, content};\n    const btn = document.getElementById('btn-go');\n    btn.disabled = true; btn.innerHTML = '<span class=\"loading-spinner\"></span> 适配中…';\n    try {\n        const r = await fetch('/api/platform', {method: 'POST', headers: {'Content-Type': 'application/json'}, body: JSON.stringify(body)}).then(r => r.json());\n        if (!r.success) { alert(r.error); btn.disabled = false; btn.innerHTML = '<i class=\"bi bi-arrow-repeat\"></i> 一键适配'; return; }\n        document.getElementById('empty').classList.add('d-none');\n        document.getElementById('result').classList.remove('d-none');\n        const d = r.data || {};\n        const tag = document.getElementById('r-source');\n        tag.className = 'source-tag ' + r.source;\n        tag.textContent = r.source === 'real' ? '真实 AI' : 'Mock';\n        document.getElementById('r-platform').textContent = safeText(d.platform) || body.platform;\n        document.getElementById('r-content').textContent = safeText(d.adapted_content) || r.raw;\n        document.getElementById('r-titles').innerHTML = (d.title_suggestions || []).map(x => `<li>${safeText(x)}</li>`).join('') || '<li class=\"text-muted\">-</li>';\n        document.getElementById('r-cover').textContent = safeText(d.cover_advice) || '-';\n        document.getElementById('r-time').textContent = safeText(d.best_publish_time) || '-';\n        document.getElementById('r-tags').innerHTML = (d.tags_suggested || []).map(t => `<span class=\"badge bg-info me-1\">${safeText(t)}</span>`).join('') || '-';\n    } catch (e) { alert('失败：' + e); }\n    btn.disabled = false; btn.innerHTML = '<i class=\"bi bi-arrow-repeat\"></i> 一键适配';\n};\n\ndocument.getElementById('btn-copy').onclick = () => {\n    navigator.clipboard.writeText(document.getElementById('r-content').textContent).then(() => alert('已复制'));\n};\n</script>\n{% endblock %}\n",
  "title_ab_test.html": "{% extends \"base.html\" %}\n{% block title %}标题 AB 测试{% endblock %}\n{% block content %}\n<div class=\"module-header\">\n    <div class=\"container\">\n        <h2><i class=\"bi bi-type-h1\"></i> 标题 AB 测试</h2>\n        <p class=\"mb-0 opacity-75\">6 个不同风格候选标题 + 点击率打分，让数据决定发哪个</p>\n    </div>\n</div>\n<div class=\"container\">\n    <div class=\"row g-4\">\n        <div class=\"col-lg-5\">\n            <div class=\"card\">\n                <div class=\"card-body\">\n                    <label class=\"form-label fw-bold\">选题 *</label>\n                    <textarea class=\"form-control\" id=\"topic\" rows=\"3\" placeholder=\"选题主题或已有的标题草稿\"></textarea>\n                    <label class=\"form-label fw-bold mt-3\">目标平台</label>\n                    <select class=\"form-select\" id=\"platform\">\n                        <option>公众号</option><option>小红书</option>\n                        <option>知乎</option><option>视频号</option>\n                    </select>\n                    <label class=\"form-label fw-bold mt-3\">生成数量</label>\n                    <input type=\"number\" class=\"form-control\" id=\"n\" value=\"6\" min=\"3\" max=\"10\">\n                    <button class=\"btn btn-primary w-100 mt-3\" id=\"btn-go\"><i class=\"bi bi-shuffle\"></i> 生成候选标题</button>\n\n                    <div class=\"tips-box mt-3 small\">\n                        <strong>🎯 标题打分维度</strong>\n                        <ul class=\"mb-0 mt-1 ps-3\">\n                            <li>点击欲（好奇心/悬念/福利钩子）</li>\n                            <li>平台算法友好度（关键词/长度）</li>\n                            <li>党味规避（不夸张、不误导）</li>\n                        </ul>\n                    </div>\n                </div>\n            </div>\n        </div>\n        <div class=\"col-lg-7\">\n            <div id=\"result\" class=\"d-none\">\n                <div class=\"card result-card mb-3\">\n                    <div class=\"card-body\">\n                        <h5>🎯 <span id=\"r-topic\"></span> <span class=\"source-tag\" id=\"r-source\"></span></h5>\n\n                        <div class=\"alert alert-success\"><strong>🏆 推荐使用：</strong> <span id=\"r-best\"></span></div>\n\n                        <div class=\"table-responsive\">\n                            <table class=\"table table-hover\">\n                                <thead><tr><th>标题</th><th style=\"width:80px;\">分数</th><th>打分理由</th><th>目标读者</th></tr></thead>\n                                <tbody id=\"r-titles\"></tbody>\n                            </table>\n                        </div>\n\n                        <h6 class=\"mt-3\">💡 优化建议</h6>\n                        <ul id=\"r-tips\"></ul>\n                    </div>\n                </div>\n            </div>\n            <div id=\"empty\" class=\"text-center text-muted py-5\">\n                <div style=\"font-size:4rem;\">📝</div>\n                <p>输入选题，AI 帮你生成 6 个候选</p>\n            </div>\n        </div>\n    </div>\n</div>\n\n<script>\n// URL 参数预填（从选题脑暴跳来）\nconst p = new URLSearchParams(location.search);\nif (p.get('topic')) document.getElementById('topic').value = p.get('topic');\n\ndocument.getElementById('btn-go').onclick = async () => {\n    const topic = document.getElementById('topic').value.trim();\n    if (!topic) { alert('请填选题'); return; }\n    const body = {topic, platform: document.getElementById('platform').value, n: document.getElementById('n').value};\n    const btn = document.getElementById('btn-go');\n    btn.disabled = true; btn.innerHTML = '<span class=\"loading-spinner\"></span> 生成中…';\n    try {\n        const r = await fetch('/api/title', {method: 'POST', headers: {'Content-Type': 'application/json'}, body: JSON.stringify(body)}).then(r => r.json());\n        if (!r.success) { alert(r.error); btn.disabled = false; btn.innerHTML = '<i class=\"bi bi-shuffle\"></i> 生成候选标题'; return; }\n        document.getElementById('empty').classList.add('d-none');\n        document.getElementById('result').classList.remove('d-none');\n        const d = r.data || {};\n        const tag = document.getElementById('r-source');\n        tag.className = 'source-tag ' + r.source;\n        tag.textContent = r.source === 'real' ? '真实 AI' : 'Mock';\n        document.getElementById('r-topic').textContent = safeText(d.topic) || topic;\n        document.getElementById('r-best').textContent = safeText(d.best) || '-';\n\n        const rows = (d.titles || []).sort((a,b)=>(Number(b.score)||0)-(Number(a.score)||0)).map(t => {\n            const score = Number(t.score) || 0;\n            return `\n            <tr>\n                <td>${safeText(t.title) || '-'}</td>\n                <td><div class=\"progress\" style=\"height:20px;\"><div class=\"progress-bar bg-${score>=90?'success':score>=80?'primary':'warning'}\" style=\"width:${score}%\">${score}</div></div></td>\n                <td class=\"small\">${safeText(t.reason) || '-'}</td>\n                <td class=\"small\">${safeText(t.audience) || '-'}</td>\n            </tr>`;\n        }).join('');\n        document.getElementById('r-titles').innerHTML = rows;\n        document.getElementById('r-tips').innerHTML = (d.tips || []).map(x => `<li>${safeText(x)}</li>`).join('') || '<li class=\"text-muted\">-</li>';\n    } catch (e) { alert('失败：' + e); }\n    btn.disabled = false; btn.innerHTML = '<i class=\"bi bi-shuffle\"></i> 生成候选标题';\n};\n</script>\n{% endblock %}\n",
  "topic_brainstorm.html": "{% extends \"base.html\" %}\n{% block title %}选题脑暴{% endblock %}\n{% block content %}\n<div class=\"module-header\">\n    <div class=\"container\">\n        <h2><i class=\"bi bi-lightbulb\"></i> 选题脑暴</h2>\n        <p class=\"mb-0 opacity-75\">输入一个主题，AI 从 6 个不同角度给出候选选题</p>\n    </div>\n</div>\n<div class=\"container\">\n    <div class=\"row g-4\">\n        <div class=\"col-lg-5\">\n            <div class=\"card\">\n                <div class=\"card-body\">\n                    <label class=\"form-label fw-bold\">创作主题 *</label>\n                    <input class=\"form-control\" id=\"topic\" placeholder=\"如：AI 副业 / 春天穿搭 / 育儿焦虑\">\n                    <label class=\"form-label fw-bold mt-3\">目标读者（可选）</label>\n                    <input class=\"form-control\" id=\"audience\" placeholder=\"如：25-35 岁职场女性\">\n                    <label class=\"form-label fw-bold mt-3\">语气（可选）</label>\n                    <select class=\"form-select\" id=\"tone\">\n                        <option value=\"\">默认</option>\n                        <option>亲切轻松</option><option>专业深度</option>\n                        <option>犀利争议</option><option>治愈温暖</option>\n                    </select>\n                    <button class=\"btn btn-primary w-100 mt-3\" id=\"btn-go\"><i class=\"bi bi-lightning-charge\"></i> 开始脑暴</button>\n                    <div class=\"tips-box mt-3 small\">\n                        <strong>💡 使用提示</strong>\n                        <ul class=\"mb-0 mt-1 ps-3\">\n                            <li>主题越具体，选题越精准</li>\n                            <li>提前在素材库上传参考文，AI 会自动引用</li>\n                            <li>heat 分数是 AI 综合平台算法的预估，仅供参考</li>\n                        </ul>\n                    </div>\n                </div>\n            </div>\n        </div>\n        <div class=\"col-lg-7\">\n            <div id=\"result\" class=\"d-none\">\n                <h5 class=\"mb-3\">✨ <span id=\"r-topic\"></span> 的 6 个选题 <span class=\"source-tag\" id=\"r-source\"></span></h5>\n                <div id=\"ideas\" class=\"row g-3\"></div>\n\n                <div class=\"mt-4 card\" id=\"kb-panel\">\n                    <div class=\"card-header\"><i class=\"bi bi-folder\"></i> 命中的私有素材</div>\n                    <div class=\"card-body\" id=\"kb-hits\"></div>\n                </div>\n            </div>\n            <div id=\"empty\" class=\"text-center text-muted py-5\">\n                <div style=\"font-size:4rem;\">💡</div>\n                <p>输入主题后，点击开始脑暴</p>\n            </div>\n        </div>\n    </div>\n</div>\n\n<script>\ndocument.getElementById('btn-go').onclick = async () => {\n    const topic = document.getElementById('topic').value.trim();\n    if (!topic) { alert('请填主题'); return; }\n    const body = {\n        topic,\n        audience: document.getElementById('audience').value,\n        tone: document.getElementById('tone').value,\n    };\n    const btn = document.getElementById('btn-go');\n    btn.disabled = true; btn.innerHTML = '<span class=\"loading-spinner\"></span> 脑暴中…';\n    try {\n        const r = await fetch('/api/topic', {method: 'POST', headers: {'Content-Type': 'application/json'}, body: JSON.stringify(body)}).then(r => r.json());\n        document.getElementById('empty').classList.add('d-none');\n        document.getElementById('result').classList.remove('d-none');\n        const d = r.data || {};\n        document.getElementById('r-topic').textContent = safeText(d.topic) || topic;\n        const tag = document.getElementById('r-source');\n        tag.className = 'source-tag ' + r.source;\n        tag.textContent = r.source === 'real' ? '真实 AI' : 'Mock';\n\n        document.getElementById('ideas').innerHTML = (d.ideas || []).map((it, i) => {\n            const title = safeText(it.title) || '-';\n            return `\n            <div class=\"col-md-6\">\n                <div class=\"card h-100\">\n                    <div class=\"card-body\">\n                        <div class=\"d-flex justify-content-between mb-2\">\n                            <span class=\"badge bg-secondary\">${safeText(it.angle) || '-'}</span>\n                            <span class=\"badge bg-warning text-dark\">🔥 ${safeText(it.heat) || 0}</span>\n                        </div>\n                        <h6 class=\"mb-2\">${title}</h6>\n                        <small class=\"text-muted\">推荐：${safeText(it.platform) || '-'} · 钩子：${safeText(it.hook) || '-'}</small>\n                        <div class=\"mt-2\"><button class=\"btn btn-sm btn-outline-primary\" onclick=\"toTitle('${title.replace(/'/g,\"\\\\'\")}')\"><i class=\"bi bi-arrow-right\"></i> AB 打分</button></div>\n                    </div>\n                </div>\n            </div>`;\n        }).join('');\n\n        const kb = document.getElementById('kb-hits');\n        if (r.kb_hits && r.kb_hits.length) {\n            kb.innerHTML = r.kb_hits.map(h => `<div class=\"border rounded p-2 mb-2\"><strong>${h.filename}</strong> <span class=\"badge bg-info\">${h.score}</span><div class=\"small text-muted mt-1\">${h.snippet.substring(0,150)}…</div></div>`).join('');\n        } else {\n            kb.innerHTML = '<small class=\"text-muted\">未命中素材（<a href=\"/library\">去上传</a>）</small>';\n        }\n    } catch (e) { alert('失败：' + e); }\n    btn.disabled = false; btn.innerHTML = '<i class=\"bi bi-lightning-charge\"></i> 开始脑暴';\n};\n\nfunction toTitle(title) {\n    location.href = '/title-ab-test?topic=' + encodeURIComponent(title);\n}\n</script>\n{% endblock %}\n",
  "viral_analysis.html": "{% extends \"base.html\" %}\n{% block title %}爆款拆解{% endblock %}\n{% block content %}\n<div class=\"module-header\">\n    <div class=\"container\">\n        <h2><i class=\"bi bi-fire\"></i> 爆款拆解</h2>\n        <p class=\"mb-0 opacity-75\">粘贴一篇爆款文本，AI 拆结构、找情绪节点、给出可复用框架</p>\n    </div>\n</div>\n<div class=\"container\">\n    <div class=\"row g-4\">\n        <div class=\"col-lg-5\">\n            <div class=\"card\">\n                <div class=\"card-body\">\n                    <ul class=\"nav nav-tabs mb-3\">\n                        <li class=\"nav-item\"><a class=\"nav-link active\" data-bs-toggle=\"tab\" href=\"#tab-paste\">粘贴文本</a></li>\n                        <li class=\"nav-item\"><a class=\"nav-link\" data-bs-toggle=\"tab\" href=\"#tab-file\">从素材库</a></li>\n                    </ul>\n                    <div class=\"tab-content\">\n                        <div class=\"tab-pane active\" id=\"tab-paste\">\n                            <textarea class=\"form-control\" id=\"content\" rows=\"12\" placeholder=\"粘贴爆款正文…\"></textarea>\n                        </div>\n                        <div class=\"tab-pane\" id=\"tab-file\">\n                            <div id=\"doc-list\">加载中…</div>\n                        </div>\n                    </div>\n                    <button class=\"btn btn-primary w-100 mt-3\" id=\"btn-go\"><i class=\"bi bi-graph-up-arrow\"></i> 开始拆解</button>\n                </div>\n            </div>\n        </div>\n        <div class=\"col-lg-7\">\n            <div id=\"result\" class=\"d-none\">\n                <div class=\"card result-card\">\n                    <div class=\"card-body\">\n                        <h5>📊 拆解结果 <span class=\"source-tag\" id=\"r-source\"></span></h5>\n\n                        <h6 class=\"mt-3\">🎯 全文结构</h6>\n                        <p class=\"badge bg-light text-dark p-2\" id=\"r-struct\"></p>\n\n                        <h6 class=\"mt-3\">💥 为什么爆</h6>\n                        <div class=\"alert alert-warning\" id=\"r-why\"></div>\n\n                        <div class=\"row g-3 mt-1\">\n                            <div class=\"col-md-6\"><h6>📌 标题技巧</h6><ul id=\"r-titletips\" class=\"small\"></ul></div>\n                            <div class=\"col-md-6\"><h6>😢 情绪节点</h6><ul id=\"r-emotion\" class=\"small\"></ul></div>\n                        </div>\n\n                        <h6>🧩 可复用框架</h6>\n                        <div class=\"alert alert-primary\" id=\"r-framework\"></div>\n\n                        <h6>💡 下次自己写的建议</h6>\n                        <ul id=\"r-sugs\"></ul>\n                    </div>\n                </div>\n            </div>\n            <div id=\"empty\" class=\"text-center text-muted py-5\">\n                <div style=\"font-size:4rem;\">🔥</div>\n                <p>粘贴爆款文本，看 AI 怎么拆解</p>\n            </div>\n        </div>\n    </div>\n</div>\n\n<script>\nlet selectedDocId = null;\nasync function loadDocs() {\n    const r = await fetch('/api/library/list').then(r => r.json());\n    const box = document.getElementById('doc-list');\n    if (!r.docs.length) { box.innerHTML = '<p class=\"small text-muted\">素材库为空，先去 <a href=\"/library\">上传</a></p>'; return; }\n    box.innerHTML = r.docs.map(d => `\n        <div class=\"form-check\">\n            <input class=\"form-check-input\" type=\"radio\" name=\"doc\" id=\"d${d.id}\" value=\"${d.id}\">\n            <label class=\"form-check-label\" for=\"d${d.id}\">${d.filename} <span class=\"badge bg-secondary\">${d.category}</span></label>\n        </div>`).join('');\n    box.querySelectorAll('input').forEach(el => el.onchange = e => selectedDocId = e.target.value);\n}\nloadDocs();\n\ndocument.getElementById('btn-go').onclick = async () => {\n    const activeTab = document.querySelector('.tab-pane.active').id;\n    const body = {};\n    if (activeTab === 'tab-paste') {\n        body.content = document.getElementById('content').value.trim();\n        if (!body.content) { alert('请粘贴文本'); return; }\n    } else {\n        if (!selectedDocId) { alert('请选文档'); return; }\n        body.doc_id = selectedDocId;\n    }\n    const btn = document.getElementById('btn-go');\n    btn.disabled = true; btn.innerHTML = '<span class=\"loading-spinner\"></span> 拆解中…';\n    try {\n        const r = await fetch('/api/viral', {method: 'POST', headers: {'Content-Type': 'application/json'}, body: JSON.stringify(body)}).then(r => r.json());\n        if (!r.success) { alert(r.error); btn.disabled = false; btn.innerHTML = '<i class=\"bi bi-graph-up-arrow\"></i> 开始拆解'; return; }\n        document.getElementById('empty').classList.add('d-none');\n        document.getElementById('result').classList.remove('d-none');\n        const d = r.data || {};\n        const tag = document.getElementById('r-source');\n        tag.className = 'source-tag ' + r.source;\n        tag.textContent = r.source === 'real' ? '真实 AI' : 'Mock';\n        document.getElementById('r-struct').textContent = safeText(d.structure) || '-';\n        document.getElementById('r-why').textContent = safeText(d.why_viral) || '-';\n        document.getElementById('r-titletips').innerHTML = (d.title_tips || []).map(x => `<li>${safeText(x)}</li>`).join('') || '<li class=\"text-muted\">-</li>';\n        document.getElementById('r-emotion').innerHTML = (d.emotion_nodes || []).map(x => `<li>${safeText(x)}</li>`).join('') || '<li class=\"text-muted\">-</li>';\n        document.getElementById('r-framework').textContent = safeText(d.framework) || '-';\n        document.getElementById('r-sugs').innerHTML = (d.suggestions || []).map(x => `<li>${safeText(x)}</li>`).join('') || '<li class=\"text-muted\">-</li>';\n    } catch (e) { alert('失败：' + e); }\n    btn.disabled = false; btn.innerHTML = '<i class=\"bi bi-graph-up-arrow\"></i> 开始拆解';\n};\n</script>\n{% endblock %}\n"
}
